import{_ as a,a as t,b as r}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as l,o as i,c as o,a2 as d}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Ajouter un canal Cloudflare R2","description":"","frontmatter":{},"headers":[],"relativePath":"fr-FR/upload/cloudflare-r2.md","filePath":"fr-FR/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),n={name:"fr-FR/upload/cloudflare-r2.md"};function u(c,e,s,p,h,m){return i(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="ajouter-un-canal-cloudflare-r2" tabindex="-1">Ajouter un canal Cloudflare R2 <a class="header-anchor" href="#ajouter-un-canal-cloudflare-r2" aria-label="Permalink to &quot;Ajouter un canal Cloudflare R2&quot;">​</a></h1><p>Le canal Cloudflare R2 enregistre les fichiers dans un bucket R2.</p><h2 id="quand-l-utiliser" tabindex="-1">Quand l’utiliser <a class="header-anchor" href="#quand-l-utiliser" aria-label="Permalink to &quot;Quand l’utiliser&quot;">​</a></h2><ul><li>Vous voulez gérer le stockage dans l’écosystème Cloudflare.</li><li>R2 sera la destination principale d’ImgBed.</li><li>Vous souhaitez combiner R2 avec un domaine personnalisé ou un CDN.</li></ul><h2 id="a-preparer" tabindex="-1">À préparer <a class="header-anchor" href="#a-preparer" aria-label="Permalink to &quot;À préparer&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Élément</th><th>Utilité</th></tr></thead><tbody><tr><td>Compte Cloudflare</td><td>Gérer R2 et les tokens</td></tr><tr><td>Bucket R2</td><td>Destination réelle des fichiers</td></tr><tr><td>Account ID</td><td>Identifier le compte</td></tr><tr><td>API Token</td><td>Autoriser lecture et écriture dans R2</td></tr><tr><td>Domaine personnalisé</td><td>Optionnel, pour des URL publiques plus propres</td></tr></tbody></table><h2 id="creer-le-bucket" tabindex="-1">Créer le bucket <a class="header-anchor" href="#creer-le-bucket" aria-label="Permalink to &quot;Créer le bucket&quot;">​</a></h2><p>Dans le Cloudflare Dashboard, ouvrez <code>R2 Object Storage</code> et créez un bucket.</p><p><img src="'+a+'" alt="Créer un bucket R2" loading="lazy"></p><p>Conservez le nom exact du bucket : il devra être saisi à l’identique dans ImgBed.</p><h2 id="trouver-l-account-id" tabindex="-1">Trouver l’Account ID <a class="header-anchor" href="#trouver-l-account-id" aria-label="Permalink to &quot;Trouver l’Account ID&quot;">​</a></h2><p>L’Account ID est visible sur la page du compte Cloudflare.</p><p><img src="'+t+'" alt="Account ID" loading="lazy"></p><h2 id="renseigner-dans-imgbed" tabindex="-1">Renseigner dans ImgBed <a class="header-anchor" href="#renseigner-dans-imgbed" aria-label="Permalink to &quot;Renseigner dans ImgBed&quot;">​</a></h2><p>Dans Paramètres d’upload, ouvrez <code>Ajouter un canal</code> et choisissez <code>Cloudflare R2</code>.</p><table tabindex="0"><thead><tr><th>Champ</th><th>Valeur</th></tr></thead><tbody><tr><td>Nom du canal</td><td>Nom facile à reconnaître</td></tr><tr><td>Account ID</td><td>Account ID Cloudflare</td></tr><tr><td>Bucket</td><td>Nom du bucket R2</td></tr><tr><td>API Token</td><td>Token ayant accès à R2</td></tr><tr><td>Domaine personnalisé</td><td>Optionnel</td></tr><tr><td>Dossier</td><td>Optionnel, souvent <code>imgbed</code></td></tr></tbody></table><h2 id="limite-de-capacite" tabindex="-1">Limite de capacité <a class="header-anchor" href="#limite-de-capacite" aria-label="Permalink to &quot;Limite de capacité&quot;">​</a></h2><p>Vous pouvez activer une limite de capacité pour contrôler quand ce canal cesse d’être utilisé.</p><p><img src="'+r+'" alt="Limite de capacité" loading="lazy"></p><p>Lorsque le seuil est atteint, ImgBed peut éviter de sélectionner ce canal pour de nouveaux uploads.</p><h2 id="verification" tabindex="-1">Vérification <a class="header-anchor" href="#verification" aria-label="Permalink to &quot;Vérification&quot;">​</a></h2><ol><li>La carte du canal R2 apparaît après enregistrement.</li><li>Le canal est activé.</li><li>Envoyez une image de test.</li><li>Vérifiez que l’objet apparaît dans le bucket.</li><li>Ouvrez le lien renvoyé par ImgBed.</li></ol><h2 id="erreurs-courantes" tabindex="-1">Erreurs courantes <a class="header-anchor" href="#erreurs-courantes" aria-label="Permalink to &quot;Erreurs courantes&quot;">​</a></h2><ul><li>Account ID ou nom de bucket incorrect.</li><li>Token sans permissions suffisantes sur le bucket.</li><li>Domaine personnalisé non relié au bucket.</li><li>Canal exclu à cause d’une limite de capacité.</li></ul>',24)])])}const _=l(n,[["render",u]]);export{k as __pageData,_ as default};
